import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { ProductDetailResponse, PublicProduct } from '../models';
import { StoreApiService } from '../services/store-api.service';
import { CartService } from '../services/cart.service';

@Component({
  selector: 'app-product-detail-page',
  standalone: true,
  imports: [CommonModule, RouterLink, FormsModule],
  template: `
    <a class="back-link" routerLink="/">← Volver al catálogo</a>

    <section *ngIf="loading" class="empty" style="margin-top:1rem;">Cargando detalle...</section>
    <section *ngIf="error" class="error" style="margin-top:1rem;">{{ error }}</section>

    <ng-container *ngIf="product && !loading">
      <div style="margin-top: 0.5rem; display: flex; gap: 1rem;">
        <a *ngIf="product.proveedor" (click)="filterByBrand()" style="cursor: pointer; color: var(--primary);">Ver más de {{ product.proveedor.nombre }}</a>
        <span *ngIf="product.categoria">|</span>
        <a *ngIf="product.categoria" (click)="filterByCategory()" style="cursor: pointer; color: var(--primary);">Ver más de {{ product.categoria.nombre }}</a>
      </div>

      <section class="detail" style="margin-top:1rem;">
        <div class="detail__panel">
          <div class="card__meta">
            {{ product.categoria?.nombre || 'Sin categoría' }} · {{ product.estado }}
          </div>
          <h1>{{ product.nombre }}</h1>
          <p>{{ product.descripcion }}</p>
          <p *ngIf="product.envio_gratis" class="free-shipping">
            Llega gratis entre el {{ freeShippingFrom }} y el {{ freeShippingTo }}
          </p>
          <p *ngIf="!product.envio_gratis" style="margin-top:1rem;">
            Llega entre el {{ freeShippingFrom }} y el {{ freeShippingTo }}
          </p>

          <p style="margin-top:1rem;">Devolución gratis. Tienes 30 días</p>

          <div style="margin-top:1rem;">
            <label>Cantidad: </label>
            <select [(ngModel)]="cantidad" (change)="onCantidadChange()" style="padding: 0.5rem; border-radius: 0.5rem; border: 1px solid var(--border);">
              <option [value]="1">1 unidad</option>
              <option [value]="2">2 unidades</option>
              <option [value]="3">3 unidades</option>
              <option [value]="4">4 unidades</option>
              <option [value]="5">5 unidades</option>
              <option [value]="moreThan5">Más de 5 unidades</option>
            </select>
          </div>

          <div style="display:flex; gap:.75rem; margin-top:1rem; flex-wrap:wrap;">
            <button type="button" class="back-link" (click)="addToCart()">Agregar al carrito</button>
            <button type="button" class="back-link" (click)="buyNow()">Comprar ahora</button>
          </div>
        </div>

        <aside class="detail__panel">
          <p><strong>Precio:</strong> S/ {{ product.precio_descuento | number:'1.2-2' }}</p>
          <p *ngIf="product.descuento_tipo">
            <strong>Descuento:</strong>
            <span *ngIf="product.descuento_tipo === 'porcentaje'; else fixedDiscount">
              {{ product.descuento_valor }}%
            </span>
            <ng-template #fixedDiscount>S/ {{ product.descuento_valor }}</ng-template>
          </p>
          <p *ngIf="product.cuotas_sin_interes">
            <strong>Cuotas:</strong> Hasta 12 cuotas sin interés de S/ {{ product.cuotas_mensual | number:'1.2-2' }}
          </p>
        </aside>
      </section>

      <section *ngIf="brandProducts.length > 0" style="margin-top:1.5rem;">
        <h2>Productos de {{ product.proveedor?.nombre }}</h2>
        <div class="carousel">
          <div class="card" *ngFor="let p of brandProducts" style="min-width: 200px;">
            <h3 class="card__title">{{ p.nombre }}</h3>
            <p><strong>S/ {{ p.precio_descuento | number:'1.2-2' }}</strong></p>
            <p class="card__meta" *ngIf="p.envio_gratis">Envío gratis</p>
          </div>
        </div>
      </section>

      <section *ngIf="relatedProducts.length > 0" style="margin-top:1.5rem;">
        <h2>Productos relacionados</h2>
        <div class="grid">
          <div class="card" *ngFor="let related of relatedProducts">
            <h3 class="card__title">{{ related.nombre }}</h3>
            <p><strong>S/ {{ related.precio_descuento | number:'1.2-2' }}</strong></p>
            <p class="card__meta" *ngIf="related.envio_gratis">Envío gratis</p>
            <div style="display:flex; justify-content:flex-end; margin-top:1rem;">
              <button type="button" class="back-link" disabled>Ver producto</button>
            </div>
          </div>
        </div>
      </section>
    </ng-container>

    <div *ngIf="showModal" class="modal-overlay" (click)="closeModal()">
      <div class="modal-content" (click)="$event.stopPropagation()">
        <h2>Agregaste a tu carrito</h2>
        <p>{{ product?.nombre }}</p>
        <p *ngIf="product?.envio_gratis" class="free-shipping">¡Tienes envío gratis!</p>
        <p *ngIf="product?.envio_gratis" style="color: var(--muted);">Aprovéchalo sumando más productos {{ product?.proveedor?.nombre }}</p>

        <h3 style="margin-top: 1rem;">Más productos de {{ product?.proveedor?.nombre }}</h3>
        <div class="modal-products-grid">
          <div class="card" *ngFor="let p of brandProducts.slice(0, 6)">
            <h4 class="card__title">{{ p.nombre }}</h4>
            <p><strong>S/ {{ p.precio_descuento | number:'1.2-2' }}</p>
          </div>
        </div>

        <div style="margin-top: 1rem; display: flex; gap: 1rem;">
          <a (click)="goToCatalog()" style="cursor: pointer; color: var(--primary);">Ver más productos {{ product?.proveedor?.nombre }}</a>
          <a (click)="goToCart()" style="cursor: pointer; color: var(--primary);">Ir al carrito</a>
        </div>
      </div>
    </div>
  `,
  styles: [`
    .free-shipping { color: #166534; font-weight: 600; }
    .carousel { display: flex; gap: 1rem; overflow-x: auto; padding: 1rem 0; }
    .modal-overlay { position: fixed; top: 0; right: 0; bottom: 0; left: 0; background: rgba(0,0,0,0.5); display: flex; justify-content: flex-end; z-index: 1000; }
    .modal-content { background: white; padding: 1.5rem; width: 400px; overflow-y: auto; }
    .modal-products-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 0.5rem; }
  `]
})
export class ProductDetailPageComponent implements OnInit {
  product: PublicProduct | null = null;
  relatedProducts: PublicProduct[] = [];
  brandProducts: PublicProduct[] = [];
  loading = true;
  error = '';
  freeShippingFrom = '';
  freeShippingTo = '';
  cantidad: number = 1;
  moreThan5 = 6;
  showModal = false;

  constructor(
    private readonly route: ActivatedRoute,
    private readonly router: Router,
    private readonly storeApi: StoreApiService,
    private readonly cart: CartService,
  ) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (!id) {
      this.error = 'No se encontró el producto solicitado.';
      this.loading = false;
      return;
    }

    this.storeApi.getProductById(id).subscribe({
      next: (response: ProductDetailResponse) => {
        this.product = response.product;
        this.relatedProducts = response.relatedProducts;
        this.freeShippingFrom = this.formatRelativeDate(2);
        this.freeShippingTo = this.formatRelativeDate(5);
        this.loading = false;
        this.loadBrandProducts();
      },
      error: () => {
        this.error = 'No se pudo cargar el producto.';
        this.loading = false;
      },
    });
  }

  private loadBrandProducts(): void {
    if (!this.product?.proveedor) return;
    this.storeApi.getCatalog({ categoria: String(this.product.categoria?.id), limit: 10 }).subscribe({
      next: (res) => {
        this.brandProducts = res.data.filter(p => p.proveedor?.id === this.product?.proveedor?.id && p.id !== this.product?.id);
      }
    });
  }

  onCantidadChange(): void {
    if (this.cantidad === this.moreThan5) {
      this.cantidad = 5;
    }
  }

  addToCart(): void {
    if (this.product) {
      for (let i = 0; i < this.cantidad; i++) {
        this.cart.addProduct(this.product);
      }
      this.showModal = true;
    }
  }

  buyNow(): void {
    if (!this.product) return;
    this.addToCart();
    this.router.navigateByUrl('/carrito');
  }

  filterByBrand(): void {
    if (this.product?.proveedor) {
      this.router.navigate(['/'], { queryParams: { search: this.product.proveedor.nombre } });
    }
  }

  filterByCategory(): void {
    if (this.product?.categoria) {
      this.router.navigate(['/'], { queryParams: { categoria: this.product.categoria.id } });
    }
  }

  closeModal(): void {
    this.showModal = false;
  }

  goToCart(): void {
    this.showModal = false;
    this.router.navigateByUrl('/carrito');
  }

  goToCatalog(): void {
    this.showModal = false;
    this.filterByBrand();
  }

  private formatRelativeDate(daysAhead: number): string {
    const date = new Date();
    date.setDate(date.getDate() + daysAhead);
    return date.toLocaleDateString('es-PE', { day: 'numeric', month: 'long' });
  }
}
